<template>

	<view class="forget-pass">
		<slideCode v-if="slideCode[0].show" :session_id="session_id[0]" @close="slideCode[0].show = false"
			@success="$slideCode_success(0, $event)"></slideCode>
		<view class="header">
			<text class="title">
				输入短信验证码
			</text>
			<view class="">
				我们已发送短信验证码到你的手机号
			</view>
		</view>
		<view class="code-input">
			<input type="text" placeholder-style="color:#d8dbe3;" placeholder="请输入验证码" v-model="code" />
			<!-- <text class="codes">获取验证码</text> -->
			<view class="codes" :style="is_sendCode?'color:#c3c8d9;':'color:red;'" @click="sendCode(10)">

				<u-verification-code :seconds="seconds" ref="uCode" @start="codeStart" @end="codeEnd"
					@change="codeChange" start-text="获取验证码" change-text="X秒"></u-verification-code>
				<view class="">
					{{tips}}
				</view>
			</view>
		</view>

		<view class="btn submit" @click="checkFrom">
			确定
		</view>
	</view>

</template>

<script>
	import slideCode from '@/components/slideCode.vue'

	export default {
		components: {
			slideCode
		},
		data() {
			return {
				list: [],
				title: '',
				type: '',
				code: '',
				user: {
					company: '',
					qq: '',
					email: '',
					password: '',
					trader_password: '',
				},
				tips: '',
				seconds: 60,
				is_sendCode: false, //是否发送验证码
				slideCode: [{
					show: false
				}],
				session_id: [], //会自动生成的
			}
		},
		onLoad(e) {
			this.type = e.type
			switch (e.type) {
				case '1':
					this.title = '修改登录密码'
					break;
				case '2':
					this.title = '修改支付密码'
					break;
			}


			uni.setNavigationBarTitle({
				title: this.title
			})

			this.$slideCode_init(0); //初始化图形滑块



		},
		methods: {
			$getRandomNunber(start, end) {
				return Math.floor(Math.random() * (end - start) + start)
			},
			$slideCode_init(index) {
				this.session_id[index] = this.$getRandomNunber(0, 999999999); //唯一id
				this.slideCode[index].yanzheng = false; //图形验证码是否验证通过
				this.slideCode[index].x = 0 //图形验证码的水平偏移值
			},
			$slideCode_success(index, data) {
				this.slideCode[index].yanzheng = true //验证通过
				this.slideCode[index].x = data.x //偏移值



				if (this.type == 1 || this.type == 2) { //发送验证码
					this.canGetCode()
				}

			},
			codeChange(text) {
				this.tips = text;
			},

			//发送验证码
			sendCode() {

				if (!this.$u.test.mobile(this.userinfo.mobile)) return this.$u.toast('请输入正确的手机号')

				this.slideCode[0].show = true; //滑块验证码


			},
			codeStart() {
				this.is_sendCode = true;
			},
			codeEnd() {
				this.is_sendCode = false;
			},
			canGetCode() {
				if (this.$refs.uCode.canGetCode) {
					// 模拟向后端请求验证码
					uni.showLoading({
						title: '正在获取验证码'
					})


					let send_type = 10
					if (this.type == 1) {
						send_type = 12
					}
					if (this.type == 2) {
						send_type = 13
					}




					let data = {
						send_type: send_type,
						mobile: this.userinfo.mobile,
						session: this.session_id[0],
					}
					this.$u.api.sendCode(data).then(res => {


						uni.hideLoading();
						// 这里此提示会被this.start()方法中的提示覆盖
						this.$u.toast('验证码已发送');
						// 通知验证码组件内部开始倒计时
						this.$refs.uCode.start();
					}).catch((res) => {
						console.log(res);
						this.$u.toast('验证码已发送');
					})



				} else {
					this.$u.toast('倒计时结束后再发送');
				}
			},
			loadData() {
				// this.$u.api.ucenterset({})
				// 	.then(res => {
				// 		this.list = res
				// 	}).catch(res => {})
			},
			checkFrom() {

				if (this.code == '') {
					this.$util.msg('请输入验证码')
					return;
				}

				let send_type = 0;
				if (this.type == 1) {
					send_type = 12
				}
				if (this.type == 2) {
					send_type = 13
				}

				this.$u.api.valiCode({
						code: this.code,
						type: send_type
					})
					.then(res => {
						switch (this.type) {
							case '1':


								this.$util.on('/pages/ucenter_sub/change?type=password&code=' + this.code)
								break;
							case '2':
								this.$util.on('/pages/ucenter_sub/change?type=trader_password&code=' + this.code)

								break;


						}

					}).catch(res => {})


				return true;
			},
			async save() {



				if (!this.user[this.type]) {
					this.$util.msg('请填写数据')
					return;
				}

				if (!this.checkFrom()) {
					return;
				}


				uni.showLoading({
					mask: true,
					title: '保存中...',

				})
				this.user.type = this.type
				this.user.code = this.code


				await this.$u.api.userinfosave(this.user)
					.then(res => {

						if (this.type == 'password' || this.type == 'trader_password') {


						} else {
							this.$u.vuex('userinfo.' + this.type, res.data);
						}

						this.$util.msg('保存成功')

						setTimeout(() => {
							//注册成功前往首页
							this.$util.back();
						}, 1500)
					}).catch(res => {})

				uni.hideLoading()
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	page {
		background-color: #f5f7fa;
		word-wrap: break-word;
		line-height: 1.3;
		font-family: Regular, Droid Sans, Droid Sans Fallback, STHeiti, SimHei, Hei;
	}

	.forget-pass {
		width: 100%;
		height: 100%;
		display: flex;
		align-items: center;
		justify-content: flex-start;
		flex-direction: column;
		gap: 46rpx;
	}

	.header {
		width: 100%;
		height: 300rpx;
		background-color: #fff;
		display: flex;
		align-items: center;
		justify-content: center;
		flex-direction: column;
		font-size: 32rpx;
		color: #818282;
	}

	.header .title {
		font-size: 46rpx;
		color: #1e2331;
		font-weight: 600;
		margin-bottom: 30rpx;
	}

	.header .mobile {
		color: #1e2331;
		font-weight: 550;
	}

	.change-pass .btn-box {
		display: flex;
		align-items: center;
		justify-content: center;
		gap: 30rpx;
		padding: 0 30rpx;
		margin-top: 66rpx;
	}

	.default {
		background: #FFFFFF;
		color: #1e2331;
	}

	.btn {
		width: 330rpx;
		height: 94rpx;
		border-radius: 48rpx;
		display: flex;
		align-items: center;
		justify-content: center;
		font-size: 30rpx;
	}

	.submit {
			background: linear-gradient(90deg, #FE8A56, #FF504B);
		color: #fff;
		width: 640rpx;
	}

	.primary {
		background: linear-gradient(90deg, #FE8A56, #FF504B);
		color: #fff;
	}

	.forget-pass .code-input {
		width: 100%;
		height: 110rpx;
		background-color: #fff;
		display: flex;
		align-items: center;
		justify-content: space-between;
		padding: 0 26rpx;
	}

	.forget-pass .code-input .codes {
		color: #ff604d;
	}
</style>
